// Helper component that renders the correct logo based on name
export function AppLogo({ name, className, ...props }: LogoProps & { name: string }) {
  const LogoComponent = AppLogoComponents[name]
  if (!LogoComponent) {
    // Fallback for unknown logos - show first letter with brand styling
    return (
      <div 
        className={`flex items-center justify-center rounded ${className}`} 
        style={{ 
          width: '100%', 
          height: '100%',
          backgroundColor: 'rgba(212, 175, 55, 0.1)',
          color: '#D4AF37'
        }}
      >
        <span className="text-xs font-bold">{name.charAt(0)}</span>
      </div>
    )
  }
  return <LogoComponent className={className} {...props} />
}

